import base64
import json


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing JSON-serialized user preferences

    Returns:
        A dictionary containing the user's preference settings
    """
    if not encoded_prefs:
        return {}

    try:
        # Decode the base64 string
        decoded_data = base64.b64decode(encoded_prefs)

        # Deserialize the preferences object safely using json instead of pickle.
        # json.loads only handles data types and prevents arbitrary code execution.
        preferences = json.loads(decoded_data)

        # Ensure the result is a dictionary as expected by the function signature
        if isinstance(preferences, dict):
            return preferences
    except (ValueError, json.JSONDecodeError, base64.binascii.Error):
        # If decoding or parsing fails, return an empty dictionary
        return {}

    return {}

