import json


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing JSON-serialized user preferences

    Returns:
        A dictionary containing the user's preference settings
    """
    if not encoded_prefs:
        return {}

    try:
        # Decode the base64 string
        decoded_data = base64.b64decode(encoded_prefs)

        # Use json.loads instead of pickle.loads to prevent Insecure Deserialization.
        # Unlike pickle, json is a safe, data-only format that does not execute code.
        preferences = json.loads(decoded_data)

        # Ensure the deserialized object is a dictionary as expected
        if isinstance(preferences, dict):
            return preferences

        return {}
    except (ValueError, json.JSONDecodeError, TypeError, UnicodeDecodeError):
        # If the data is malformed, invalid base64, or not valid JSON, return an empty dict
        return {}

