import base64
import json


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string safely using JSON.

    Args:
        encoded_prefs: A base64-encoded string containing JSON-serialized user preferences

    Returns:
        A dictionary containing the user's preference settings. 
        Returns an empty dict if decoding fails or input is empty.
    """
    if not encoded_prefs:
        return {}

    try:
        # Decode the base64 string
        decoded_data = base64.b64decode(encoded_prefs)

        # Deserialize the preferences object using json instead of pickle
        # json.loads is safe as it only parses data structures and does not execute code
        preferences = json.loads(decoded_data)

        if isinstance(preferences, dict):
            return preferences
        return {}

    except (json.JSONDecodeError, ValueError, TypeError, base64.binascii.Error):
        # Handle cases where the cookie is malformed or not valid base64/JSON
        return {}

